# Simulating UK civil service categorization
def categorize_employee(employee_type, country):
    if country == "UK":
        if employee_type == "Crown employee":
            return "Civil servant"
        elif employee_type == "Local authority employee":
            return "Local government officer"
    else:
        return "Public servant"

# Example usage
print(categorize_employee("Crown employee", "UK"))  # Output: Civil servant
print(categorize_employee("Local authority employee", "UK"))  # Output: Local government officer
print(categorize_employee("Any government employee", "USA"))  # Output: Public servant
